Code.Terraform:
```hcl
resource "azurerm_kubernetes_cluster" "<example_resource_name>" {
  name                      = "<example_resource_name>"
  location                  = "<example_resource_id>"
  resource_group_name       = "<example_resource_id>"
  dns_prefix                = "<example_resource_name>"
  automatic_upgrade_channel = "stable"  # Critical: enables automatic cluster upgrades

  default_node_pool {
    name       = "default"
    node_count = 1
    vm_size    = "Standard_DS2_v2"
  }

  identity {
    type = "SystemAssigned"
  }
}
```
